import{_ as o,c as a,o as r,a1 as t}from"./chunks/framework.DILC4Csi.js";const b=JSON.parse('{"title":"О проекте: Введение в OpenCodeDocs | opencodedocs","description":"Узнайте о OpenCodeDocs, первом учебном сайте экосистемы ИИ. Глубокий анализ проектов с открытым исходным кодом, предоставление высококачественных руководств, управляемых исходным кодом и 100% работоспособных.","frontmatter":{"title":"О проекте: Введение в OpenCodeDocs | opencodedocs","sidebarTitle":"Узнайте о нашем видении","subtitle":"О проекте: Введение в OpenCodeDocs | opencodedocs","description":"Узнайте о OpenCodeDocs, первом учебном сайте экосистемы ИИ. Глубокий анализ проектов с открытым исходным кодом, предоставление высококачественных руководств, управляемых исходным кодом и 100% работоспособных."},"headers":[],"relativePath":"ru/about.md","filePath":"ru/about.md"}'),n={name:"ru/about.md"};function s(i,e,c,d,l,p){return r(),a("div",null,[...e[0]||(e[0]=[t('<h1 id="о-opencodedocs" tabindex="-1">О OpenCodeDocs <a class="header-anchor" href="#о-opencodedocs" aria-label="Permalink to &quot;О OpenCodeDocs&quot;">​</a></h1><blockquote><p><strong>Первый учебный сайт экосистемы ИИ · Управляемый исходным кодом · 100% работоспособный</strong></p></blockquote><h2 id="наше-видение" tabindex="-1">Наше видение <a class="header-anchor" href="#наше-видение" aria-label="Permalink to &quot;Наше видение&quot;">​</a></h2><p>Инструменты ИИ развиваются невероятно быстро, официальная документация отстает, а онлайн-руководства устаревают — мы хотим это изменить.</p><p>OpenCodeDocs глубоко анализирует исходный код и официальные примеры проектов с открытым исходным кодом, выделяет основную логику и гарантирует работоспособность каждой строки кода с помощью автоматической проверки.</p><p>При обновлении проектов наши руководства синхронизируются. Каждое руководство четко указывает версию Git Commit, чтобы вы знали, на основе какой версии был создан код.</p><p><strong>Наша цель — стать «Verified Standard» в мире инструментов ИИ.</strong></p><h2 id="лицензия-с-открытым-исходным-кодом" tabindex="-1">Лицензия с открытым исходным кодом <a class="header-anchor" href="#лицензия-с-открытым-исходным-кодом" aria-label="Permalink to &quot;Лицензия с открытым исходным кодом&quot;">​</a></h2><p>Мы верим, что открытость порождает доверие. Приветствуем вклад сообщества, исправление ошибок и дополнение материалов.</p><h3 id="содержание-руководств" tabindex="-1">Содержание руководств <a class="header-anchor" href="#содержание-руководств" aria-label="Permalink to &quot;Содержание руководств&quot;">​</a></h3><p><strong>Лицензия</strong>: <a href="https://creativecommons.org/licenses/by-nc-sa/4.0/deed.ru" target="_blank" rel="noreferrer">CC-BY-NC-SA 4.0</a><br> Атрибуция — Некоммерческое использование — На тех же условиях. Разрешается воспроизведение и адаптация, но с обязательным указанием источника, без коммерческих целей и при условии распространения по той же лицензии.</p><h3 id="инструменты-сборки" tabindex="-1">Инструменты сборки <a class="header-anchor" href="#инструменты-сборки" aria-label="Permalink to &quot;Инструменты сборки&quot;">​</a></h3><p><strong>VitePress</strong>: Этот проект создан с использованием <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a>.<br> Благодарим команду VitePress за предоставление такого превосходного генератора статических сайтов.</p><p><a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">Посмотреть репозиторий на GitHub</a></p><h2 id="связаться-с-нами" tabindex="-1">Связаться с нами <a class="header-anchor" href="#связаться-с-нами" aria-label="Permalink to &quot;Связаться с нами&quot;">​</a></h2><ul><li><strong>Email</strong>: <a href="mailto:vbgatecom@gmail.com" target="_blank" rel="noreferrer">vbgatecom@gmail.com</a></li><li><strong>Twitter</strong>: <a href="https://x.com/codingzys" target="_blank" rel="noreferrer">@codingzys</a></li><li><strong>GitHub</strong>: <a href="https://github.com/vbgate/opencodedocs" target="_blank" rel="noreferrer">github.com/vbgate/opencodedocs</a></li></ul>',16)])])}const u=o(n,[["render",s]]);export{b as __pageData,u as default};
